// Derive slug from company name (client_name field contains the company/client name).
// If the payment platform sends a separate company_name field, prefer that;
// otherwise fall back to client_name (expected to be the company name, e.g. 'Meridian Consulting Group').
const input = $input.first().json;
const raw = input.company_name || input.client_name || '';
const slug = raw.toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .trim();
return [{ json: { ...input, client_slug: slug } }];

// Prospect lookup result (HTTP GET — always returns {records: [...]})
const lookupResult = $input.first().json;
const records = lookupResult.records || [];
const prospect = records.length > 0 ? records[0].fields : {};
const prospect_record_id = records.length > 0 ? records[0].id : null;

const originalData = $('Derive Client Slug').first().json;
const clientTierMap = {
  'starter-package': 'starter-build',
  'starter-build': 'starter-build',
  'growth-package': 'growth-build',
  'growth-build': 'growth-build',
  'scale-retainer': 'scale-build',
  'scale-package': 'scale-build',
  'scale-build': 'scale-build',
  'retainer': 'retainer',
  'agency-retainer': 'agency-retainer',
};
const rawTier = prospect.service_tier || originalData.service_tier || originalData.package || null;
const service_tier = rawTier ? (clientTierMap[String(rawTier).trim()] || 'starter-build') : null;

return [{ json: {
  ...originalData,
  lead_score_grade:          prospect.lead_score_grade            || null,
  pre_call_brief:            prospect['Precall Brief']             || null,
  industry:                  prospect.industry                     || null,
  prospect_record_id:        prospect_record_id,
  scope_of_work:             prospect.scope_of_work                || null,
  scope_summary:             prospect.scope_summary                || null,
  service_tier,
  tools_required:            prospect.tools_required               || null,
  automation_count:          prospect.automation_count             || null,
  automation_1_name:         prospect.automation_1_name            || null,
  automation_1_description:  prospect.automation_1_description     || null,
  automation_2_name:         prospect.automation_2_name            || null,
  automation_2_description:  prospect.automation_2_description     || null,
  automation_3_name:         prospect.automation_3_name            || null,
  automation_3_description:  prospect.automation_3_description     || null,
  call_notes:                prospect.call_notes                   || null
} }];

// Community edition: n8n Projects requires enterprise.
// Generate the naming convention string only — no API call.
const data = $input.first().json;
const workspace_name = "[PA] " + data.client_slug;
return [{ json: { ...data, id: workspace_name } }];

const response = $input.first().json;
const priorData = $('Extract Client Record ID').first().json;
const workspace_id = response.id;
if (!workspace_id) {
  throw new Error("workspace_id missing — expected naming convention string");
}
return [{ json: { ...priorData, workspace_id } }];

const airtableResult = $input.first().json;
const priorData = $('Extract Workspace ID').first().json;

// Primary: parse scope_of_work markdown for tools section
const scopeRaw = airtableResult.fields?.scope_of_work || airtableResult.scope_of_work || '';
let tools_required = [];

if (scopeRaw) {
  const lines = scopeRaw.split('\n');
  let inToolsSection = false;
  for (const line of lines) {
    if (/tools.required/i.test(line)) { inToolsSection = true; continue; }
    if (inToolsSection) {
      if (/^#{1,3}\s/.test(line)) break;
      const match = line.match(/^[-*]\s+(.+)/);
      if (match) tools_required.push(match[1].trim());
    }
  }
}

// Fallback 1: tools_required field from Read Scope of Work result
const rawTools = airtableResult.fields?.tools_required || airtableResult.tools_required;
if (tools_required.length === 0 && rawTools) {
  if (Array.isArray(rawTools)) {
    tools_required = rawTools;
  } else if (typeof rawTools === 'string') {
    try { tools_required = JSON.parse(rawTools); }
    catch(e) { tools_required = rawTools.split(',').map(t => t.trim()).filter(Boolean); }
  }
}

// Fallback 2: tools_required from Merge Airtable Context (already in pipeline)
if (tools_required.length === 0) {
  const mergeCtx = $('Merge Airtable Context').first().json;
  const ctxTools = mergeCtx.tools_required;
  if (ctxTools && typeof ctxTools === 'string') {
    tools_required = ctxTools.split(',').map(t => t.trim()).filter(Boolean);
  }
}

if (tools_required.length === 0) {
  // Graceful degradation: continue with empty list, log warning
  console.warn('tools_required is empty — continuing with empty credentials checklist');
  tools_required = [];
}

return [{ json: { ...priorData, tools_required } }];

// Community edition: generate a credentials checklist JSON.
// Each tool in tools_required gets status "pending_client_setup".
const data = $input.first().json;
const tools = Array.isArray(data.tools_required) ? data.tools_required
  : String(data.tools_required).split(",").map(t => t.trim()).filter(Boolean);

const credentials_checklist = {};
tools.forEach(tool => {
  const k = tool.toLowerCase().replace(/[^a-z0-9]/g, "_");
  credentials_checklist[k] = { tool, status: "pending_client_setup" };
});

const checklist_id = "creds-checklist-" + data.client_slug;
return [{ json: { ...data, id: checklist_id, credentials_checklist } }];

const response = $input.first().json;
const credentials_template_id = response.id;
if (!credentials_template_id) {
  throw new Error("credentials_template_id missing");
}
const credentials_checklist = response.credentials_checklist || {};
return [{ json: { ...response, credentials_template_id, credentials_checklist } }];

let priorData;
try {
  priorData = $('Extract All Task IDs').first().json;
} catch (e) {
  priorData = $input.first().json || $('Extract Template ID').first().json;
}

function fromNode(name, field) {
  try { return $(name).first().json[field] || null; } catch (e) { return null; }
}

const clickup_folder_id = priorData.clickup_folder_id || fromNode('Extract Folder ID', 'clickup_folder_id');
const clickup_list_onboarding = priorData.clickup_list_onboarding || fromNode('Create List — Onboarding', 'id');
const clickup_list_build = priorData.clickup_list_build || fromNode('Create List — Build', 'id');
const clickup_list_qa = priorData.clickup_list_qa || fromNode('Create List — QA', 'id');
const clickup_list_live = priorData.clickup_list_live || fromNode('Create List — Live', 'id');

return [{ json: { ...priorData, clickup_folder_id, clickup_list_onboarding, clickup_list_build, clickup_list_qa, clickup_list_live } }];

const errorData = $input.first().json;
const priorData = $('Extract Template ID').first().json;
console.log('ClickUp folder creation failed (non-blocking):', JSON.stringify(errorData));
return [{ json: { ...priorData, clickup_folder_id: null, clickup_error: errorData.message || 'ClickUp folder creation failed', clickup_list_onboarding: null, clickup_list_build: null, clickup_list_qa: null, clickup_list_live: null } }];

