// Webhook wraps POST body under .body — flatten to root
const item = $input.first().json;
return [{ json: item.body || item }];

const folderData = $input.first().json;
const priorData = $('Extract Template ID').first().json;
const clickup_folder_id = String(folderData.id || '');
if (!clickup_folder_id) throw new Error('ClickUp folder creation returned no ID');
return [{ json: { ...priorData, clickup_folder_id } }];

// Read all task IDs from previous nodes
const ob_welcome = $('Seed Task: OB — Welcome').first().json.id || null;
const ob_internal = $('Seed Task: OB — Internal').first().json.id || null;
const ob_airtable = $('Seed Task: OB — Airtable').first().json.id || null;
const ob_credentials = $('Seed Task: OB — Credentials').first().json.id || null;
const ob_tools_connected = $('Seed Task: OB — Tools Connected').first().json.id || null;
const ob_credentials_tested = $('Seed Task: OB — Credentials Tested').first().json.id || null;
const ob_build_ready = $('Seed Task: OB — Build Ready').first().json.id || null;
const build_started = $('Seed Task: Build — Started').first().json.id || null;
const build_complete = $('Seed Task: Build — Owner Review').first().json.id || null;
const qa_checklist = $('Seed Task: QA — Checklist').first().json.id || null;
const qa_report = $('Seed Task: QA — Report').first().json.id || null;
const qa_verdict = $('Seed Task: QA — Verdict').first().json.id || null;
const qa_fixes = $('Seed Task: QA — Fixes').first().json.id || null;
const qa_activation_review = $('Seed Task: QA — Activation Review').first().json.id || null;
const live_activated = $('Seed Task: Live — Activated').first().json.id || null;
const live_airtable_updated = $('Seed Task: Live — Airtable Updated').first().json.id || null;
const live_launch_date = $('Seed Task: Live — Launch Date').first().json.id || null;
const live_client_notified = $('Seed Task: Live — Client Notified').first().json.id || null;
const live_status_confirmed = $('Seed Task: Live — Status Confirmed').first().json.id || null;
const live_cleanup = $('Seed Task: Live — Cleanup').first().json.id || null;
const live_workflow_ids = $('Seed Task: Live — Workflow IDs').first().json.id || null;

// Get prior data from Extract Template ID node
const priorData = $('Extract Template ID').first().json;

return [{
  json: {
    ...priorData,
    clickup_task_ob_welcome: ob_welcome,
    clickup_task_ob_internal: ob_internal,
    clickup_task_ob_airtable: ob_airtable,
    clickup_task_ob_credentials: ob_credentials,
    clickup_task_ob_tools_connected: ob_tools_connected,
    clickup_task_ob_credentials_tested: ob_credentials_tested,
    clickup_task_ob_build_ready: ob_build_ready,
    clickup_task_build_started: build_started,
    clickup_task_build_complete: build_complete,
    clickup_task_qa_checklist: qa_checklist,
    clickup_task_qa_report: qa_report,
    clickup_task_qa_verdict: qa_verdict,
    clickup_task_qa_fixes: qa_fixes,
    clickup_task_qa_activation_review: qa_activation_review,
    clickup_task_live_activated: live_activated,
    clickup_task_live_airtable_updated: live_airtable_updated,
    clickup_task_live_launch_date: live_launch_date,
    clickup_task_live_client_notified: live_client_notified,
    clickup_task_live_status_confirmed: live_status_confirmed,
    clickup_task_live_cleanup: live_cleanup,
    clickup_task_live_workflow_ids: live_workflow_ids
  }
}];

const excluded = ['test-complete', 'closed.no_deal', 'closed.post_delivery'];
const atData = $('Fetch All Client Slugs').item.json;
const wfData = $input.first().json;

const slugs = (atData.records || [])
  .filter(r => r.fields.client_slug && !excluded.includes(r.fields.project_status))
  .map(r => r.fields.client_slug)
  .sort();

const nodes = (wfData.nodes || []).map(n => {
  if (n.name !== 'Scope Call Form') return n;
  return {
    ...n,
    parameters: {
      ...n.parameters,
      formFields: {
        values: [
          { fieldLabel: 'Client slug', fieldType: 'dropdown', fieldOptions: { values: slugs.map(s => ({ option: s })) }, requiredField: true },
          { fieldLabel: 'Company name', requiredField: true },
          { fieldLabel: 'Industry', placeholder: 'e.g. Health & Wellness' },
          { fieldLabel: 'Call notes', fieldType: 'textarea', placeholder: 'What does the client do? What manual tasks eat their time? What tools do they use? How big is their team? Any urgency or blockers mentioned?', requiredField: true }
        ]
      }
    }
  };
});

const s = wfData.settings || {};
return [{ json: {
  name: wfData.name,
  nodes,
  connections: wfData.connections,
  settings: {
    ...(s.executionOrder && { executionOrder: s.executionOrder }),
    ...(s.callerPolicy && { callerPolicy: s.callerPolicy }),
    ...(s.errorWorkflow && { errorWorkflow: s.errorWorkflow }),
    ...(s.saveManualExecutions !== undefined && { saveManualExecutions: s.saveManualExecutions }),
    ...(s.timezone && { timezone: s.timezone })
  },
  staticData: wfData.staticData || null
}}];

// POST response has the new Airtable client record
const createResult = $input.first().json;
const priorData = $('Merge Airtable Context').first().json;

// If create failed, airtable_record_id will be null — downstream Update will skip gracefully
const airtable_record_id = createResult.id || null;

return [{ json: { ...priorData, airtable_record_id } }];

const records = $('Fetch Active Clients').first().json.records || [];
const valid = records.filter(r => r.fields?.clickup_folder_id && String(r.fields.clickup_folder_id).trim() !== '');
if(valid.length === 0) return [{ json: { _no_clients: true } }];
return valid.map(r => ({
  json: {
    airtable_record_id: r.id,
    client_name: r.fields.company_name || '',
    client_email: r.fields.email || '',
    clickup_folder_id: r.fields.clickup_folder_id || '',
    client_slug: r.fields.client_slug || '',
    contact_name: r.fields.contact_name || ''
  }
}));

// runOnceForAllItems — one item per client (each has client fields + tasks array)
const sevenDaysAgo = Date.now() - 7 * 24 * 60 * 60 * 1000;

return $input.all().map(item => {
  const d = item.json;
  const tasks = Array.isArray(d.tasks) ? d.tasks : [];

  const completed = tasks
    .filter(t => {
      const s = (t.status?.status || '').toLowerCase();
      const updated = t.date_updated ? new Date(parseInt(t.date_updated)).getTime() : 0;
      return ['complete','done','closed'].includes(s) && updated > sevenDaysAgo;
    })
    .map(t => String(t.name || ''));

  const inProgress = tasks
    .filter(t => {
      const s = (t.status?.status || '').toLowerCase();
      return ['in progress','in review','doing','to do','open','not started'].includes(s);
    })
    .map(t => String(t.name || ''));

  const blocked = tasks
    .filter(t => {
      const s = (t.status?.status || '').toLowerCase();
      return ['blocked','on hold'].includes(s);
    })
    .map(t => String(t.name || ''));

  const upcoming = tasks
    .filter(t => t.due_date && new Date(parseInt(t.due_date)) > Date.now())
    .sort((a, b) => parseInt(a.due_date) - parseInt(b.due_date))
    .slice(0, 1)
    .map(t => String(t.name || ''));

  return {
    json: {
      airtable_record_id: String(d.airtable_record_id || ''),
      client_name:        String(d.client_name        || ''),
      client_email:       String(d.client_email       || ''),
      clickup_folder_id: String(d.clickup_folder_id || ''),
      client_slug:        String(d.client_slug        || ''),
      completed:    completed.join('\n')  || 'None this week',
      inProgress:   inProgress.join('\n') || 'None',
      blocked:      blocked.join('\n')    || 'None',
      nextMilestone: upcoming[0]          || 'No upcoming milestones set'
    }
  };
});

// Pull Claude's text response and wrap it in the Phoenix Automation HTML template
const claudeItems = $input.all();
const clientItems = $('Build Claude Payload').all();

function parseSection(text, header) {
  // Find the section and extract lines until next section or end
  const lines = text.split('\n');
  let capturing = false;
  const result = [];
  for (const line of lines) {
    if (line.trim().toUpperCase() === header.toUpperCase()) {
      capturing = true;
      continue;
    }
    if (capturing) {
      if (/^[A-Z\s]{4,}$/.test(line.trim()) && line.trim() !== '') break;
      if (line.trim() === '---') break;
      if (line.trim()) result.push(line.trim().replace(/^[-•]\s*/, ''));
    }
  }
  return result;
}

function bulletLines(items) {
  if (!items.length) return '<p style="margin:0;color:#666;">None this week</p>';
  return items.map(i =>
    '<p style="margin:0 0 6px 0;">• ' + i + '</p>'
  ).join('');
}

return claudeItems.map((item, i) => {
