const body = $input.first().json.body || $input.first().json;
const answers = (body.form_response || body).answers || [];
const submitted_at = (body.form_response || body).submitted_at || new Date().toISOString();

function getAnswer(ref) {
  const a = answers.find(a => a.field && a.field.ref === ref);
  if (!a) return null;
  if (a.type === 'text') return a.text;
  if (a.type === 'number') return a.number;
  if (a.type === 'choice') return a.choice && a.choice.label;
  return null;
}

return [{ json: {
  full_name:     getAnswer('full_name')    || '',
  business_name: getAnswer('business_name') || '',
  industry:      getAnswer('industry')      || '',
  team_size:     getAnswer('team_size')     || 0,
  pain_point:    getAnswer('pain_point')    || '',
  hours_lost:    getAnswer('hours_lost')    || 0,
  email:         getAnswer('email')         || '',
  submitted_at
}}];

