  // Duplicate path — IF true passes Check Duplicate output
  record_id = data.records.length > 0 ? data.records[0].id : null;
  is_new = false;
} else {
  // New record path — Set New Record Data output
  record_id = data.record_id || null;
  is_new = data.is_new !== undefined ? data.is_new : true;
}

const prompt = [
  'You are a lead qualification agent for Phoenix Automation, an AI automation agency.',
  'Score this inbound lead using the following rules.',
  '',
  'Score each dimension 0-2:',
  '- Industry fit: 0 = out of ICP, 1 = adjacent, 2 = core ICP (Professional Services, Trades, Health, Retail, Marketing Agency)',
  '- Team size: 0 = <3 or >200, 1 = 3-10, 2 = 10-200',
  '- Pain specificity: 0 = vague, 1 = named pain, 2 = named and quantified',
  '- Time lost: 0 = not sure, 1 = <5 hrs/week, 2 = 5+ hrs/week',
  '',
  'Lead data:',
  'Industry: ' + extracted.industry,
  'Team size: ' + extracted.team_size,
  'Pain point: ' + extracted.pain_point,
  'Hours lost per week: ' + extracted.hours_lost,
  '',
  'Return ONLY compact valid JSON. No markdown, no reasoning, no extra text:',
  '{',
  '  "score_total": <0-8>,',
  '  "score_grade": "<A/B/C/D>",',
  '  "grade_logic": "A=7-8, B=5-6, C=3-4, D=0-2",',
  '  "pre_call_brief": "<2-3 sentence brief for Kai to read before the assessment call. Include: what the business does, their main pain, team size, and one recommended angle to open the call with.>"',
  '}'
].join('\n');

return [{ json: {
  ...extracted,
  record_id,
  is_new,
  claude_payload: JSON.stringify({
    model: 'z-ai/glm-4.5-air:free',
    max_tokens: 350,
    reasoning: { effort: 'none', exclude: true }, messages: [{ role: 'user', content: prompt }]
  })
}}];

