  const cleaned = text.replace(/\`\`\`json\n?/g, '').replace(/\`\`\`\n?/g, '').trim();
  const m = cleaned.match(/\{[\s\S]*?\}/);
  if (m) {
    const p = JSON.parse(m[0]);
    score_total = Number.isFinite(Number(p.score_total)) ? Number(p.score_total) : 0;
