    hours_saved_per_week: parseFloat(r.fields.hours_saved_per_week) || 0
  }
}));

const d = $input.first().json;
const slug = String(d.client_slug || d.client_name || 'unknown');
console.log('No workflow IDs for client:', slug, '— using zero metrics');
return [{
  json: {
    airtable_record_id: String(d.airtable_record_id || ''),
    client_name:        String(d.client_name        || ''),
    client_email:       String(d.client_email       || ''),
    client_slug:        slug,
    executions:         [],
    execution_summary:  'No workflows tracked yet for this client'
  }
}];

const executionResponses = $input.all();
const clients = $('Split Client Records').all();

return executionResponses.map((item, i) => {
  const execData = item.json;
  const client = clients[i] ? clients[i].json : {};
  const executions = execData.data || [];
  return {
    json: {
      ...client,
      executions
    }
  };
});

return $input.all().map(item => {
  const d = item.json;
  const executions = Array.isArray(d.executions) ? d.executions : [];

  const total = executions.length;
  const successful = executions.filter(e => e.status === 'success').length;
  const failed = executions.filter(e => e.status === 'error').length;
  const uptime = total > 0 ? ((successful / total) * 100).toFixed(1) : '100.0';

  // Rough estimate: hours_saved_per_week / ~20 runs per week
  const hoursPerWeek = d.hours_saved_per_week || 0;
  const timeSaved = hoursPerWeek > 0
    ? (successful * (hoursPerWeek / 20)).toFixed(1)
    : (successful * 0.05).toFixed(1);

  const errorMessages = [...new Set(
    executions
      .filter(e => e.status === 'error')
      .map(e => {
        try { return e.data.resultData.error.message; } catch(ex) { return 'Unknown error'; }
      })
      .filter(Boolean)
  )].slice(0, 3);

  return {
    json: {
      airtable_record_id: String(d.airtable_record_id || ''),
      client_name:        String(d.client_name        || ''),
      client_email:       String(d.client_email       || ''),
      client_slug:        String(d.client_slug        || ''),
      total_executions:   total,
      successful_executions: successful,
      failed_executions:  failed,
      uptime_pct:         uptime,
      time_saved_hours:   timeSaved,
      error_types:        errorMessages.join('; ') || 'None',
      execution_summary:  d.execution_summary || null
    }
  };
});

return $input.all().map(item => {
  const d = item.json;

  const lastMonth = new Date();
  lastMonth.setMonth(lastMonth.getMonth() - 1);
  const reportPeriod = lastMonth.toLocaleDateString('en-US', { month: 'long', year: 'numeric' });


const noDataNote = d.execution_summary ? `\n\nNote: ${d.execution_summary}` : '';
const prompt = [
    'Write a monthly automation performance report for a client of Phoenix Automation.',
    'Professional tone, plain language. Under 300 words. Data-first.',
    '',
    'Client: ' + String(d.client_name || ''),
    'Report period: ' + reportPeriod,
    '',
    'Data:',
    '- Total automation runs: ' + d.total_executions,
    '- Successful runs: ' + d.successful_executions,
    '- Uptime: ' + d.uptime_pct + '%',
    '- Errors caught and handled: ' + d.failed_executions,
    '- Estimated time saved: ' + d.time_saved_hours + ' hours',
    '- Error types (if any): ' + d.error_types,
    '',
    'Structure:',
    '1. One sentence on what the automations accomplished this month',
    '2. Performance table (runs, uptime, time saved)',
    '3. If errors > 0: brief plain-language note on what was caught and handled',
    '4. One-sentence closing that reinforces ongoing value',
    '5. End with: \'Questions about your automations? Reply here.\'',
    '',
    'Do not invent data. If a metric is zero, state it.'
  ].join('\n') + noDataNote;

  return {
    json: {
      ...d,
      report_period: reportPeriod,
      claude_payload: JSON.stringify({
        model: 'z-ai/glm-4.5-air:free',
        max_tokens: 600,
        reasoning: { effort: 'none', exclude: true }, messages: [{ role: 'user', content: prompt }]
      })
    }
  };
});

const claudeItems = $input.all();
const clientItems = $('Build Claude Payload').all();

return claudeItems.map((item, i) => {
  const c = clientItems[i] ? clientItems[i].json : {};
  const reportBody = item.json.choices?.[0]?.message?.content || item.json.content?.[0]?.text || item.json.text || 'Report generation failed — please check automation logs.';

  const clientName = String(c.client_name || 'there');
  const period = c.report_period || 'this month';
  const subject = clientName + ' \u2014 Automation Report ' + period;

  const bodyHtml = reportBody
    .split('\n')
    .map(line => line.trim()
      ? '<p style="margin:0 0 10px 0;font-size:15px;color:#1a1a1a;line-height:1.7;">' + line + '</p>'
      : '')
    .join('\n');

  const html = [
    '<!DOCTYPE html>',
    '<html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>',
    '<body style="margin:0;padding:0;background:#f0f0f0;font-family:Arial,sans-serif;">',
    '<table width="100%" cellpadding="0" cellspacing="0" style="background:#f0f0f0;padding:32px 0;">',
    '<tr><td align="center">',
    '<table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;background:#ffffff;border-radius:6px;overflow:hidden;">',
    '<tr><td style="background:#1B2A4A;padding:28px 32px;">',
    '<p style="margin:0;font-size:20px;font-weight:bold;color:#ffffff;letter-spacing:0.02em;">Phoenix Automation</p>',
    '<p style="margin:6px 0 0 0;font-size:13px;color:#8899bb;letter-spacing:0.04em;text-transform:uppercase;">Monthly Performance Report \u2014 ' + period + '</p>',
    '</td></tr>',
    '<tr><td style="padding:28px 32px 0 32px;">',
    '<p style="margin:0 0 16px 0;font-size:15px;color:#1a1a1a;line-height:1.6;">Hi ' + clientName + ',</p>',
    '</td></tr>',
    '<tr><td style="padding:12px 32px 32px 32px;">',
    bodyHtml,
    '</td></tr>',
    '<tr><td style="background:#f5f5f5;padding:18px 32px;border-top:1px solid #e5e5e5;">',
    '<p style="margin:0;font-size:13px;color:#888888;text-align:center;">Phoenix Automation &nbsp;&middot;&nbsp; Reply to this email with any questions</p>',
    '</td></tr>',
    '</table></td></tr></table>',
    '</body></html>'
  ].join('\n');

  return {
    json: {
      airtable_record_id: String(c.airtable_record_id || ''),
      client_name:        clientName,
      client_email:       String(c.client_email        || ''),
      total_executions:   c.total_executions  || 0,
      failed_executions:  c.failed_executions || 0,
      email_html:         html,
      email_subject:      subject
    }
  };
});

const records = $input.first().json.records || [];
const now = new Date();

return records.map(rec => {
  const fields = rec.fields || {};
  const startedAt = fields.onboarding_started_at ? new Date(fields.onboarding_started_at) : null;
  const hoursOverdue = startedAt ? Math.floor((now - startedAt) / 3600000) - 48 : null;
  return {
    json: {
      record_id: rec.id,
