const data = $input.item.json;
const status = data.project_status;
const now = new Date().toISOString();

const actions = {
  task_updates: [],
  email: null,
  airtable_update: null,
  skip: false
};

function addTask(taskId, newStatus) {
  if (taskId && taskId.trim()) {
    actions.task_updates.push({ task_id: taskId.trim(), new_status: newStatus });
  }
}

switch(status) {
  case 'onboarding.in_progress': {
    if (data.onboarding_started_at) {
      const startedAt = new Date(data.onboarding_started_at);
      const hoursSince = (Date.now() - startedAt.getTime()) / (1000 * 60 * 60);
      const lastFlagged = data.overdue_flagged_at ? new Date(data.overdue_flagged_at) : null;
      const hoursSinceFlagged = lastFlagged ? (Date.now() - lastFlagged.getTime()) / (1000 * 60 * 60) : 999;
      if (hoursSince > 48 && !data.clickup_task_ob_credentials_tested && hoursSinceFlagged > 24) {
        actions.email = {
          subject: '[PA] Onboarding stalled — ' + data.company_name,
          body: data.company_name + ' has been in onboarding for more than 48 hours.\n\nCredentials may not be connected yet.\n\nClient email: ' + data.email + '\nOnboarding started: ' + data.onboarding_started_at + '\n\nAction: Check ClickUp onboarding list and follow up with client.'
        };
        actions.airtable_update = { overdue_flagged_at: now };
      }
    }
    break;
  }
  case 'build.ready':
    addTask(data.clickup_task_ob_build_ready, 'complete');
    break;
  case 'build.in_progress':
    addTask(data.clickup_task_build_started, 'in progress');
    break;
  case 'build.blocked':
    actions.email = {
      subject: '[PA] Build blocked — ' + data.company_name,
      body: 'The workflow build for ' + data.company_name + ' is blocked.\n\nCheck the BUILD BLOCKED comment on the ClickUp Build task for details.\n\nAction required before build can resume.'
    };
    break;
  case 'build.complete':
    addTask(data.clickup_task_build_started, 'complete');
    addTask(data.clickup_task_build_complete, 'in progress');
    break;
  case 'qa.in_progress':
    addTask(data.clickup_task_build_complete, 'complete');
    addTask(data.clickup_task_qa_checklist, 'in progress');
    addTask(data.clickup_task_qa_report, 'in progress');
    break;
  case 'qa.pass':
    addTask(data.clickup_task_qa_checklist, 'complete');
    addTask(data.clickup_task_qa_report, 'complete');
    addTask(data.clickup_task_qa_verdict, 'complete');
    addTask(data.clickup_task_live_activated, 'in progress');
    actions.email = {
      subject: '[PA] QA passed — ' + data.company_name + ' ready to activate',
      body: data.company_name + ' has passed QA.\n\nVerdict: ' + (data.qa_verdict || 'PASS') + '\n\nAction: Review qa-report.md then activate workflows in n8n.\nAfter activation, update project_status to live in Airtable.'
    };
    break;
  case 'qa.fail':
    addTask(data.clickup_task_qa_verdict, 'in progress');
    actions.email = {
      subject: '[PA] QA failed — ' + data.company_name,
      body: data.company_name + ' QA has failed.\n\nVerdict: ' + (data.qa_verdict || 'FAIL') + '\n\nAction: Review qa-report.md. workflow-builder-agent will fix and re-run QA automatically.'
    };
    break;
  case 'activation.pending':
    addTask(data.clickup_task_live_activated, 'in progress');
    break;
  case 'live':
    addTask(data.clickup_task_live_activated, 'complete');
    addTask(data.clickup_task_live_airtable_updated, 'complete');
    if (data.project_launch_date) addTask(data.clickup_task_live_launch_date, 'complete');
    if (data.last_status_update_sent_at) addTask(data.clickup_task_live_status_confirmed, 'complete');
    if (data.n8n_workflow_ids) addTask(data.clickup_task_live_workflow_ids, 'complete');
    break;
  default:
    actions.skip = true;
}

return { json: { ...data, sync_actions: actions, sync_timestamp: now } };

