    break;
  case 'qa.pass':
    addTask(data.clickup_task_qa_checklist, 'complete');
    addTask(data.clickup_task_qa_report, 'complete');
    addTask(data.clickup_task_qa_verdict, 'complete');
    addTask(data.clickup_task_live_activated, 'in progress');
    actions.email = {
      subject: '[PA] QA passed — ' + data.company_name + ' ready to activate',
      body: data.company_name + ' has passed QA.\n\nVerdict: ' + (data.qa_verdict || 'PASS') + '\n\nAction: Review qa-report.md then activate workflows in n8n.\nAfter activation, update project_status to live in Airtable.'
    };
    break;
  case 'qa.fail':
    addTask(data.clickup_task_qa_verdict, 'in progress');
    actions.email = {
      subject: '[PA] QA failed — ' + data.company_name,
      body: data.company_name + ' QA has failed.\n\nVerdict: ' + (data.qa_verdict || 'FAIL') + '\n\nAction: Review qa-report.md. workflow-builder-agent will fix and re-run QA automatically.'
    };
    break;
  case 'activation.pending':
    addTask(data.clickup_task_live_activated, 'in progress');
    break;
  case 'live':
    addTask(data.clickup_task_live_activated, 'complete');
    addTask(data.clickup_task_live_airtable_updated, 'complete');
    if (data.project_launch_date) addTask(data.clickup_task_live_launch_date, 'complete');
    if (data.last_status_update_sent_at) addTask(data.clickup_task_live_status_confirmed, 'complete');
    if (data.n8n_workflow_ids) addTask(data.clickup_task_live_workflow_ids, 'complete');
    break;
  default:
    actions.skip = true;
}

return { json: { ...data, sync_actions: actions, sync_timestamp: now } };

const data = $input.first().json;
const updates = data.sync_actions.task_updates || [];

return updates.map(upd => ({
  json: {
    client_record_id: data.record_id,
    company_name: data.company_name,
    task_id: upd.task_id,
    new_status: upd.new_status,
    sync_actions: data.sync_actions,
    sync_timestamp: data.sync_timestamp,
    _original: data
  }
}));
